import "./AdminComponents.css";
import React, { useState, useEffect } from 'react';
import { Plus, Trash2, X, Image } from 'lucide-react';
import toast from 'react-hot-toast';
import { getGalleryImages, createGalleryImage, deleteGalleryImage } from '../../lib/supabase';

const CATS = ['food', 'ambiance', 'events'];

const EMPTY = { image_url: '', caption: '', category: 'food', sort_order: 0 };

export default function AdminGallery() {
  const [images, setImages]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal]     = useState(false);
  const [form, setForm]       = useState(EMPTY);
  const [saving, setSaving]   = useState(false);
  const [preview, setPreview] = useState('');

  const load = () => {
    setLoading(true);
    getGalleryImages().then(({ data }) => {
      setImages(data || []);
      setLoading(false);
    });
  };

  useEffect(() => { load(); }, []);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSave = async (e) => {
    e.preventDefault();
    if (!form.image_url) { toast.error('Image URL is required.'); return; }
    setSaving(true);
    const { error } = await createGalleryImage(form);
    setSaving(false);
    if (error) { toast.error(error.message); return; }
    toast.success('Image added to gallery!');
    setModal(false);
    setForm(EMPTY);
    setPreview('');
    load();
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Remove this image from the gallery?')) return;
    const { error } = await deleteGalleryImage(id);
    if (error) { toast.error(error.message); return; }
    toast.success('Image removed.');
    load();
  };

  return (
    <div>
      <div className="admin-section-head">
        <div>
          <h2>Gallery</h2>
          <p>{images.length} images across all categories</p>
        </div>
        <button className="btn btn-primary" onClick={() => { setForm(EMPTY); setPreview(''); setModal(true); }}>
          <Plus size={15} /> Add Image
        </button>
      </div>

      {loading ? <div className="spinner" /> : (
        <>
          {CATS.map(cat => {
            const catImages = images.filter(i => i.category === cat);
            if (catImages.length === 0) return null;
            return (
              <div key={cat} style={{ marginBottom: 32 }}>
                <h3 style={{ fontFamily:'var(--font-display)', fontSize:16, color:'var(--charcoal)', marginBottom:14, textTransform:'capitalize', display:'flex', alignItems:'center', gap:8 }}>
                  {cat} <span style={{ fontSize:12, color:'var(--text-muted)', fontFamily:'var(--font-body)', fontWeight:400 }}>({catImages.length})</span>
                </h3>
                <div className="gallery-admin-grid">
                  {catImages.map(img => (
                    <div key={img.id} className="gallery-admin-item">
                      <img src={img.image_url} alt={img.caption || cat} loading="lazy"
                        onError={e => { e.target.src = 'https://via.placeholder.com/300x200?text=Image+Error'; }} />
                      <div className="gallery-admin-item__overlay">
                        <p>{img.caption || '—'}</p>
                        <button onClick={() => handleDelete(img.id)}>
                          <Trash2 size={16} /> Remove
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
          {images.length === 0 && (
            <div style={{ textAlign:'center', padding:'60px 0', background:'#fff', borderRadius:'var(--radius)', border:'1px solid var(--border)' }}>
              <Image size={40} style={{ color:'var(--text-muted)', margin:'0 auto 12px' }} />
              <p style={{ color:'var(--text-muted)', fontStyle:'italic' }}>No images yet. Add your first gallery image.</p>
            </div>
          )}
        </>
      )}

      {/* Modal */}
      {modal && (
        <div className="admin-modal-overlay">
          <div className="admin-modal">
            <div className="admin-modal__header">
              <h3>Add Gallery Image</h3>
              <button className="admin-modal__close" onClick={() => setModal(false)}><X size={18} /></button>
            </div>
            <form onSubmit={handleSave}>
              <div className="admin-modal__body">
                <div className="form-group">
                  <label>Image URL *</label>
                  <input required className="form-input" placeholder="https://..."
                    value={form.image_url}
                    onChange={e => { set('image_url', e.target.value); setPreview(e.target.value); }} />
                </div>
                {preview && (
                  <div style={{ borderRadius:'var(--radius-sm)', overflow:'hidden', height:180 }}>
                    <img src={preview} alt="Preview" style={{ width:'100%', height:'100%', objectFit:'cover' }}
                      onError={() => setPreview('')} />
                  </div>
                )}
                <div className="form-group">
                  <label>Caption</label>
                  <input className="form-input" placeholder="e.g. Our signature Mohinga"
                    value={form.caption} onChange={e => set('caption', e.target.value)} />
                </div>
                <div className="admin-form-grid">
                  <div className="form-group">
                    <label>Category</label>
                    <select className="form-input" value={form.category} onChange={e => set('category', e.target.value)}>
                      {CATS.map(c => <option key={c} value={c}>{c.charAt(0).toUpperCase()+c.slice(1)}</option>)}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Sort Order</label>
                    <input type="number" className="form-input" placeholder="0"
                      value={form.sort_order} onChange={e => set('sort_order', parseInt(e.target.value) || 0)} />
                  </div>
                </div>
              </div>
              <div className="admin-modal__footer">
                <button type="button" className="btn btn-outline" onClick={() => setModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>
                  {saving ? 'Adding...' : 'Add to Gallery'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
